    case 10:
        printf("Ottimo\n");
        /* manca break — continua nel caso 9! */
    case 9:
        printf("Buono\n");
        break;
}
/* Se voto è 10, stampa sia "Ottimo" che "Buono" */
Metti sempre break alla fine di ogni caso, incluso default.













