Considera questo codice:
#include &lt;stdio.h&gt;
#include &lt;string.h&gt;

void leggiNome() {
    char nome[10];   /* buffer di 10 caratteri */
    printf("Inserisci il tuo nome: ");
    gets(nome);      /* PERICOLOSO — legge senza limiti */
    printf("Ciao, %s!\n", nome);
}

int main() {
    leggiNome();
    return 0;
}
gets legge caratteri dalla tastiera e li scrive in nome senza mai controllare quanti ne arrivano. Se l’utente scrive 50 caratteri invece di 10, i 40 caratteri in eccesso vengono scritti oltre i confini dell’array in zone di memoria che appartengono ad altre variabili o al sistema.


Quando una funzione viene chiamata, il sistema crea uno stack frame, una zona di memoria che contiene le variabili locali e l’indirizzo di ritorno (dove tornare dopo la funzione).
STACK FRAME di leggiNome():
┌─────────────────────┐
│ nome[0]  ... nome[9]│  ← buffer — 10 byte
├─────────────────────┤
│ altre variabili     │  ← qui arrivano i dati in eccesso
├─────────────────────┤
│ indirizzo di ritorno│  ← se sovrascritto, il programma va dove vuole l'attaccante
└─────────────────────┘
Se l’attaccante scrive abbastanza dati da raggiungere l’indirizzo di ritorno e lo sovrascrive con un indirizzo scelto da lui, il programma continuera l’esecuzione da quel punto eseguendo codice arbitrario.






Importantgets è stata rimossa dal C moderno



La funzione gets è cosi pericolosa che è stata rimossa dallo standard C11. Il compilatore moderno ti avvisa quando la usi. Non usarla mai: usa sempre fgets con il limite di dimensione.
gets(nome);                          /* PERICOLOSO — mai usare */
fgets(nome, sizeof(nome), stdin);    /* sicuro */

Vediamo un programma volutamente vulnerabile per capire cosa succede:
#include &lt;stdio.h&gt;
#include &lt;string.h&gt;

int main() {
    int autorizzato = 0;
    char password[8];

    printf("Inserisci la password: ");
    scanf("%s", password);   /* non controlla la lunghezza */

    if (strcmp(password, "segreto") == 0) {
        autorizzato = 1;
    }

    if (autorizzato) {
        printf("Accesso consentito!\n");
    } else {
        printf("Accesso negato.\n");
    }

    return 0;
}
Questo programma sembra corretto. Ma considera la disposizione in memoria:
MEMORIA LOCALE:
┌─────────────┐
│ password[8] │  ← 8 byte per la password
├─────────────┤
│ autorizzato │  ← subito dopo in memoria
└─────────────┘
Se l’utente inserisce una stringa piu lunga di 8 caratteri, scanf continua a scrivere oltre password sovrascrivendo autorizzato. Se autorizzato diventa diverso da 0, la condizione if (autorizzato) è vera e l’accesso è consentito anche senza la password corretta.






NoteQuesto e solo a scopo didattico



L’esempio mostra il principio. Nella realtà moderna i sistemi operativi hanno protezioni come ASLR (Address Space Layout Randomization) e stack canaries che rendono questi attacchi molto piu difficili ma non impossibili.

Una matrice in C è un array di array. Pensala come una tabella: righe e colonne. Ogni elemento è identificato da due indici: [riga][colonna].
int m[3][4];
Significa: - 3 righe - 4 colonne - totale elementi = 3 × 4 = 12 - ogni elemento è int
È memoria contigua: come un array monodimensionale ma più grande. Gli elementi sono disposti riga per riga in memoria.






int m[3][4];          /* matrice di interi, 3 righe, 4 colonne */
double tabella[5][5]; /* matrice quadrata di double */
Con #define per le dimensioni — sempre consigliato:
#define RIGHE 3
#define COLONNE 4

int m[RIGHE][COLONNE];



Forma “tabella” — più leggibile:
int m[3][3] = {
    {1, 2, 3},
    {4, 5, 6},
    {7, 8, 9}
};
Forma lineare — equivalente:
int m[2][3] = {1, 2, 3, 4, 5, 6};
Entrambe generano la stessa struttura in memoria.
Azzerare tutto:
int m[3][4] = {0};   /* tutti gli elementi a 0 */



m[0][2]   /* riga 0, colonna 2 */
m[1][3]   /* riga 1, colonna 3 */
Prima l’indice riga, poi l’indice colonna. Come dire: “vai alla riga 0, poi alla colonna 2”.






ImportantGli indici partono da 0



Una matrice m[RIGHE][COLONNE] ha righe da 0 a RIGHE-1 e colonne da 0 a COLONNE-1. Uscire da questi limiti è un errore.
int m[3][4];
m[3][0] = 1;   /* ERRORE — la riga 3 non esiste */
m[0][4] = 1;   /* ERRORE — la colonna 4 non esiste */







Questo è il cuore di quasi tutto: se non sai fare questo, non puoi fare né somme né ricerche.
Lo schema mentale deve essere: per ogni riga, scorri tutte le colonne.
int i, j;
for (i = 0; i &lt; RIGHE; i++) {
    for (j = 0; j &lt; COLONNE; j++) {
        /* lavoro su m[i][j] */
    }
}


int i, j;
for (i = 0; i &lt; RIGHE; i++) {
    for (j = 0; j &lt; COLONNE; j++) {
        printf("m[%d][%d]: ", i, j);
        scanf("%d", &m[i][j]);
    }
}



int i, j;
for (i = 0; i &lt; RIGHE; i++) {
    for (j = 0; j &lt; COLONNE; j++) {
        printf("%4d", m[i][j]);
    }
    printf("\n");   /* a capo dopo ogni riga */
}
Output (per la matrice 3×3 con valori 1-9):
   1   2   3
   4   5   6
   7   8   9



int somma = 0;
for (i = 0; i &lt; RIGHE; i++) {
    for (j = 0; j &lt; COLONNE; j++) {
        somma += m[i][j];
    }
}
printf("Somma: %d\n", somma);



int max = m[0][0];
for (i = 0; i &lt; RIGHE; i++) {
    for (j = 0; j &lt; COLONNE; j++) {
        if (m[i][j] &gt; max)
            max = m[i][j];
    }
}
printf("Massimo: %d\n", max);



int r = 1;   /* seconda riga */
int s = 0;
for (j = 0; j &lt; COLONNE; j++) {
    s += m[r][j];
}
printf("Somma riga %d: %d\n", r, s);



int c = 2;   /* terza colonna */
int s = 0;
for (i = 0; i &lt; RIGHE; i++) {
    s += m[i][c];
}
printf("Somma colonna %d: %d\n", c, s);



/* La diagonale principale ha i == j */
int s = 0;
for (i = 0; i &lt; RIGHE; i++) {
    s += m[i][i];
}
printf("Somma diagonale: %d\n", s);





Quando passi una matrice a una funzione, devi specificare almeno la dimensione delle colonne.
void stampa(int m[][4], int righe) {
    int i, j;
    for (i = 0; i &lt; righe; i++) {
        for (j = 0; j &lt; 4; j++) {
            printf("%4d", m[i][j]);
        }
        printf("\n");
    }
}
Uso: stampa(m, 3);






NotePerché bisogna specificare le colonne?



La memoria è contigua riga per riga. Per sapere dove inizia la riga i, il compilatore deve calcolare l’offset: i * numero_colonne. Senza sapere quante colonne ci sono, non può fare questo calcolo.
Il numero di righe invece puoi passarlo come parametro, come facevi con gli array monodimensionali.




/* Somma tutti gli elementi */
int somma(int m[][COLONNE], int righe) {
    int i, j, s = 0;
    for (i = 0; i &lt; righe; i++)
        for (j = 0; j &lt; COLONNE; j++)
            s += m[i][j];
    return s;
}

/* Trova il massimo */
int massimo(int m[][COLONNE], int righe) {
    int i, j, max = m[0][0];
    for (i = 0; i &lt; righe; i++)
        for (j = 0; j &lt; COLONNE; j++)
            if (m[i][j] &gt; max)
                max = m[i][j];
    return max;
}

/* Stampa la matrice */
void stampa(int m[][COLONNE], int righe) {
    int i, j;
    for (i = 0; i &lt; righe; i++) {
        for (j = 0; j &lt; COLONNE; j++)
            printf("%4d", m[i][j]);
        printf("\n");
    }
}





Puoi usare sizeof per calcolare dimensioni e indici — ma solo nello stesso scope in cui la matrice è dichiarata, non dentro le funzioni.
int m[3][4];

int totale_byte  = sizeof(m);             /* 3*4*4 = 48 byte */
int byte_riga    = sizeof(m[0]);          /* 4*4   = 16 byte */
int byte_elem    = sizeof(m[0][0]);       /* 4 byte */

