#include &lt;stdio.h&gt;

int* trovaPari(int v[], int n) {
    int *p = v;
    int i;

    for (i = 0; i &lt; n; i++) {
        if (*p % 2 == 0)
            return p;
        p++;
    }

    return NULL;
}

int main() {
    int v[5] = {1, 3, 5, 8, 9};
    int *ris = trovaPari(v, 5);

    if (ris != NULL)
        printf("%d\n", *ris);
    else
        printf("Nessun pari\n");

    return 0;
}

