#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;time.h&gt;

int main() {
    int segreto, tentativo, tentativi;

    /* Genera un numero casuale tra 1 e 100 */
    srand(time(NULL));
    segreto = rand() % 100 + 1;

    tentativi = 0;

    printf("Ho scelto un numero tra 1 e 100. Indovina!\n\n");

    do {
        printf("Tentativo: ");
        scanf("%d", &tentativo);
