    FILE *f = fopen("frasi.txt", "r");
    if (f == NULL) {
        printf("Errore apertura file.\n");
        return 1;
    }

    char riga[200];
    int righe = 0;

    while (fgets(riga, sizeof(riga), f) != NULL) {
        righe++;
    }

    fclose(f);
    printf("Righe nel file: %d\n", righe);

