NoteCosa significa log2(N)?



log2(N) e il numero di volte che devi dimezzare N per arrivare a 1. - log2(8) = 3 perche 8 → 4 → 2 → 1 (tre dimezzamenti) - log2(1024) = 10 perche servono 10 dimezzamenti - log2(1.000.000) ≈ 20
Questo spiega perche la ricerca binaria e cosi veloce: raddoppiare la dimensione dell’array aggiunge solo un confronto in piu.






#include &lt;stdio.h&gt;
#include &lt;string.h&gt;

#define N 5

typedef struct {
    char nome[50];
    char telefono[20];
} Contatto;

/* Ordina per nome con Bubble Sort */
void ordinaPerNome(Contatto v[], int n) {
    int i, j;
    Contatto temp;
    for (i = 0; i &lt; n - 1; i++) {
        for (j = 0; j &lt; n - 1 - i; j++) {
            if (strcmp(v[j].nome, v[j+1].nome) &gt; 0) {
                temp     = v[j];
                v[j]     = v[j+1];
                v[j+1]   = temp;
            }
        }
    }
}

/* Ricerca binaria per nome */
int cercaContatto(Contatto v[], int n, const char nome[]) {
    int sin = 0, des = n - 1, mid, cmp;
    while (sin &lt;= des) {
        mid = (sin + des) / 2;
        cmp = strcmp(v[mid].nome, nome);
        if (cmp == 0)  return mid;
        if (cmp &lt; 0)   sin = mid + 1;
        else           des = mid - 1;
    }
    return -1;
}

int main() {
    Contatto rubrica[N] = {
        {"Mario",   "333-1111"},
        {"Alice",   "333-2222"},
        {"Sara",    "333-3333"},
        {"Marco",   "333-4444"},
        {"Lucia",   "333-5555"}
    };

    /* Ordino prima di cercare */
    ordinaPerNome(rubrica, N);

    char cercato[50];
    printf("Cerca contatto: ");
    fgets(cercato, sizeof(cercato), stdin);
    cercato[strcspn(cercato, "\n")] = '\0';

    int pos = cercaContatto(rubrica, N, cercato);

    if (pos != -1)
        printf("Trovato: %s → %s\n",
            rubrica[pos].nome, rubrica[pos].telefono);
    else
        printf("Contatto non trovato.\n");

    return 0;
}




